import{_ as e,o,c as t,R as a}from"./chunks/framework.g9eZ-ZSs.js";const u=JSON.parse('{"title":"Knockout Overview","description":"","frontmatter":{},"headers":[],"relativePath":"stacks/ko/overview.md","filePath":"stacks/ko/overview.md"}'),i={name:"stacks/ko/overview.md"},r=a('<h1 id="knockout-overview" tabindex="-1">Knockout Overview <a class="header-anchor" href="#knockout-overview" aria-label="Permalink to &quot;Knockout Overview&quot;">​</a></h1><p>The <a href="https://knockoutjs.com/" target="_blank" rel="noreferrer">Knockout</a> stack for Coalesce offers the ability to build pages with the time-tested <a href="https://knockoutjs.com/" target="_blank" rel="noreferrer">Knockout</a> JavaScript library using all of the features of the Coalesce generated APIs and <a href="/Coalesce/stacks/disambiguation/view-model.html">ViewModels</a>. It can be used for anything between adding simple interactive augmentations of MVC pages to building a full MPA-SPA hybrid application.</p><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>Check out <a href="/Coalesce/stacks/ko/getting-started.html">Getting Started with Knockout</a> if you haven&#39;t already to learn how to get a new Coalesce Knockout project up and running.</p><h2 id="generated-code" tabindex="-1">Generated Code <a class="header-anchor" href="#generated-code" aria-label="Permalink to &quot;Generated Code&quot;">​</a></h2><p>Below you will find a brief overview of each of the different pieces of code that Coalesce will generate for you when you choose the Knockout stack.</p><h3 id="typescript" tabindex="-1">TypeScript <a class="header-anchor" href="#typescript" aria-label="Permalink to &quot;TypeScript&quot;">​</a></h3><p>Coalesce generates a number of different types of TypeScript classes to support your data through the generated API.</p><h4 id="viewmodels" tabindex="-1"><a href="/Coalesce/stacks/ko/client/view-model.html">ViewModels</a> <a class="header-anchor" href="#viewmodels" aria-label="Permalink to &quot;[ViewModels](/stacks/ko/client/view-model.md)&quot;">​</a></h4><p>One view model class is generated for each of your <a href="/Coalesce/modeling/model-types/entities.html">Entity Models</a> and <a href="/Coalesce/modeling/model-types/dtos.html">Custom DTOs</a>. These models contain fields for your model <a href="/Coalesce/modeling/model-components/properties.html">Properties</a>, and functions and other members for your model <a href="/Coalesce/modeling/model-components/methods.html">Methods</a>. They also contain a number of standard fields &amp; functions inherited from <code>BaseViewModel</code> which offer basic loading &amp; saving functionality, as well as other handy utility members for use with Knockout.</p><p>See <a href="/Coalesce/stacks/ko/client/view-model.html">TypeScript ViewModels</a> for more details.</p><h4 id="list-viewmodels" tabindex="-1"><a href="/Coalesce/stacks/ko/client/list-view-model.html">List ViewModels</a> <a class="header-anchor" href="#list-viewmodels" aria-label="Permalink to &quot;[List ViewModels](/stacks/ko/client/list-view-model.md)&quot;">​</a></h4><p>One ListViewModel is generated for each of your <a href="/Coalesce/modeling/model-types/entities.html">Entity Models</a> and <a href="/Coalesce/modeling/model-types/dtos.html">Custom DTOs</a>. These classes contain functionality for loading sets of objects from the server. They provide searching, paging, sorting, and filtering functionality.</p><p>See <a href="/Coalesce/stacks/ko/client/list-view-model.html">TypeScript ListViewModels</a> for more details.</p><h4 id="external-type-viewmodels" tabindex="-1"><a href="/Coalesce/stacks/ko/client/external-view-model.html">External Type ViewModels</a> <a class="header-anchor" href="#external-type-viewmodels" aria-label="Permalink to &quot;[External Type ViewModels](/stacks/ko/client/external-view-model.md)&quot;">​</a></h4><p>Any non-primitive types which are not themselves a <a href="/Coalesce/modeling/model-types/entities.html">Entity Models</a> or <a href="/Coalesce/modeling/model-types/dtos.html">Custom DTOs</a> which are accessible through the aforementioned types, either through one of its <a href="/Coalesce/modeling/model-components/properties.html">Properties</a>, or return value from one of its <a href="/Coalesce/modeling/model-components/methods.html">Methods</a>, will have a corresponding TypeScript ViewModel generated for it. These ViewModels only provide a <code>KnockoutObservable</code> field for each property on the C# class.</p><p>See <a href="/Coalesce/stacks/ko/client/external-view-model.html">TypeScript External ViewModels</a> for more details.</p><h3 id="view-controllers" tabindex="-1">View Controllers <a class="header-anchor" href="#view-controllers" aria-label="Permalink to &quot;View Controllers&quot;">​</a></h3><p>For each of your <a href="/Coalesce/modeling/model-types/entities.html">Entity Models</a> and <a href="/Coalesce/modeling/model-types/dtos.html">Custom DTOs</a>, a controller is created in the <code>/Controllers/Generated</code> directory of your web project. These controllers provide routes for the generated admin views.</p><p>As you add your own pages to your application, you should add additional partial classes in the <code>/Controllers</code> that extend these generated partial classes to expose those pages.</p><h3 id="admin-views" tabindex="-1">Admin Views <a class="header-anchor" href="#admin-views" aria-label="Permalink to &quot;Admin Views&quot;">​</a></h3><p>For each of your <a href="/Coalesce/modeling/model-types/entities.html">Entity Models</a> and <a href="/Coalesce/modeling/model-types/dtos.html">Custom DTOs</a>, a number of views are generated to provide administrative-level access to your data.</p><h4 id="table" tabindex="-1">Table <a class="header-anchor" href="#table" aria-label="Permalink to &quot;Table&quot;">​</a></h4><p>Provides a basic table view with sorting, searching, and paging of your data. Can be rendered in either read-only mode (routed as <code>/Table</code>), or editable mode (routed as <code>TableEdit</code>).</p><h4 id="cards" tabindex="-1">Cards <a class="header-anchor" href="#cards" aria-label="Permalink to &quot;Cards&quot;">​</a></h4><p>Provides a card-based view of your data with searching and paging.</p><h4 id="createedit" tabindex="-1">CreateEdit <a class="header-anchor" href="#createedit" aria-label="Permalink to &quot;CreateEdit&quot;">​</a></h4><p>Provides an editor view which can be used to create new entities or edit existing ones.</p><h4 id="editorhtml" tabindex="-1">EditorHtml <a class="header-anchor" href="#editorhtml" aria-label="Permalink to &quot;EditorHtml&quot;">​</a></h4><p>Provides a minimal amount of HTML to display an editor for the object type. This is used by the <code>showEditor</code> method on the generated TypeScript ViewModels.</p>',30),s=[r];function l(d,n,c,h,m,p){return o(),t("div",null,s)}const w=e(i,[["render",l]]);export{u as __pageData,w as default};
